#!/usr/bin/env python3
import os
import sys
import hashlib
import shutil
import json
import time

MINIGIT_DIR = ".minigit"
OBJECTS_DIR = os.path.join(MINIGIT_DIR, "objects")
INDEX_FILE = os.path.join(MINIGIT_DIR, "index")
HEAD_FILE = os.path.join(MINIGIT_DIR, "HEAD")
REFS_DIR = os.path.join(MINIGIT_DIR, "refs")
MASTER_REF = os.path.join(REFS_DIR, "master")

def init():
    if os.path.exists(MINIGIT_DIR):
        print("Initialized empty minigit repository (existing)", file=sys.stderr)
        return
    os.makedirs(OBJECTS_DIR, exist_ok=True)
    os.makedirs(REFS_DIR, exist_ok=True)
    with open(HEAD_FILE, "w") as f:
        f.write("ref: refs/master\n")
    with open(MASTER_REF, "w") as f:
        f.write("")
    with open(INDEX_FILE, "w") as f:
        f.write("{}")
    print("Initialized empty minigit repository", file=sys.stderr)

def hash_object(data):
    sha = hashlib.sha1(data.encode()).hexdigest()
    path = os.path.join(OBJECTS_DIR, sha)
    with open(path, "w") as f:
        f.write(data)
    return sha

def update_index(args):
    if len(args) < 1:
        print("usage: minigit update-index <file>...", file=sys.stderr)
        sys.exit(1)
    try:
        with open(INDEX_FILE, "r") as f:
            index = json.load(f)
    except:
        index = {}
    for fname in args:
        if not os.path.exists(fname):
            print(f"error: '{fname}' does not exist", file=sys.stderr)
            sys.exit(1)
        with open(fname, "r") as f:
            content = f.read()
        sha = hash_object(content)
        index[fname] = sha
    with open(INDEX_FILE, "w") as f:
        json.dump(index, f)

def write_tree():
    try:
        with open(INDEX_FILE, "r") as f:
            index = json.load(f)
    except:
        index = {}
    tree_entries = []
    for fname, sha in sorted(index.items()):
        tree_entries.append(f"{sha} {fname}")
    tree_content = "\n".join(tree_entries)
    tree_sha = hash_object(tree_content)
    print(tree_sha)

def commit_tree(args):
    if len(args) < 3 or args[1] != "-m":
        print("usage: minigit commit-tree <sha> -m <message>", file=sys.stderr)
        sys.exit(1)
    tree_sha = args[0]
    message = args[2]
    try:
        with open(HEAD_FILE, "r") as f:
            head_ref = f.read().strip()
        if head_ref.startswith("ref: "):
            ref_path = os.path.join(MINIGIT_DIR, head_ref[5:])
            if os.path.exists(ref_path):
                with open(ref_path, "r") as f:
                    parent = f.read().strip()
            else:
                parent = ""
        else:
            parent = head_ref
    except:
        parent = ""
    timestamp = int(time.time())
    commit_content = f"tree {tree_sha}\n"
    if parent:
        commit_content += f"parent {parent}\n"
    commit_content += f"timestamp {timestamp}\n"
    commit_content += f"{message}"
    commit_sha = hash_object(commit_content)
    with open(HEAD_FILE, "r") as f:
        head_ref = f.read().strip()
    if head_ref.startswith("ref: "):
        ref_path = os.path.join(MINIGIT_DIR, head_ref[5:])
        with open(ref_path, "w") as f:
            f.write(commit_sha)
    print(commit_sha)

def update_ref(args):
    if len(args) < 2:
        print("usage: minigit update-ref <ref> <sha>", file=sys.stderr)
        sys.exit(1)
    ref = args[0]
    sha = args[1]
    if ref == "HEAD":
        ref_path = HEAD_FILE
    else:
        ref_path = os.path.join(MINIGIT_DIR, ref)
    with open(ref_path, "w") as f:
        f.write(sha)

def get_commit_sha(commit):
    if commit == "HEAD":
        with open(HEAD_FILE, "r") as f:
            head_ref = f.read().strip()
        if head_ref.startswith("ref: "):
            ref_path = os.path.join(MINIGIT_DIR, head_ref[5:])
            with open(ref_path, "r") as f:
                return f.read().strip()
        else:
            return head_ref
    else:
        return commit

def read_object(sha):
    path = os.path.join(OBJECTS_DIR, sha)
    with open(path, "r") as f:
        return f.read()

def get_tree_from_commit(commit_sha):
    commit_data = read_object(commit_sha)
    lines = commit_data.splitlines()
    tree_line = lines[0]
    tree_sha = tree_line.split()[1]
    return tree_sha

def ls_tree(args):
    if len(args) < 1:
        print("usage: minigit ls-tree <sha>", file=sys.stderr)
        sys.exit(1)
    tree_sha = args[0]
    tree_data = read_object(tree_sha)
    for line in tree_data.splitlines():
        if " " in line:
            sha, fname = line.split(" ", 1)
            print(f"{fname}")

def read_tree(args):
    if len(args) < 1:
        print("usage: minigit read-tree <sha>", file=sys.stderr)
        sys.exit(1)
    tree_sha = args[0]
    tree_data = read_object(tree_sha)
    try:
        with open(INDEX_FILE, "r") as f:
            index = json.load(f)
    except:
        index = {}
    for line in tree_data.splitlines():
        if " " in line:
            sha, fname = line.split(" ", 1)
            obj_path = os.path.join(OBJECTS_DIR, sha)
            with open(obj_path, "r") as f:
                content = f.read()
            with open(fname, "w") as f:
                f.write(content)
            index[fname] = sha
    with open(INDEX_FILE, "w") as f:
        json.dump(index, f)

def merge_tree(args):
    if len(args) < 1:
        print("usage: minigit merge-tree <sha>", file=sys.stderr)
        sys.exit(1)
    tree_sha = args[0]
    tree_data = read_object(tree_sha)
    try:
        with open(INDEX_FILE, "r") as f:
            index = json.load(f)
    except:
        index = {}
    for line in tree_data.splitlines():
        if " " in line:
            sha, fname = line.split(" ", 1)
            if fname not in index:
                obj_path = os.path.join(OBJECTS_DIR, sha)
                with open(obj_path, "r") as f:
                    content = f.read()
                with open(fname, "w") as f:
                    f.write(content)
                index[fname] = sha
    with open(INDEX_FILE, "w") as f:
        json.dump(index, f)

def main():
    if len(sys.argv) < 2:
        print("usage: minigit <command> [args]", file=sys.stderr)
        sys.exit(1)
    command = sys.argv[1]
    args = sys.argv[2:]
    if command == "init":
        init()
    elif command == "update-index":
        update_index(args)
    elif command == "write-tree":
        write_tree()
    elif command == "commit-tree":
        commit_tree(args)
    elif command == "update-ref":
        update_ref(args)
    elif command == "ls-tree":
        ls_tree(args)
    elif command == "read-tree":
        read_tree(args)
    elif command == "merge-tree":
        merge_tree(args)
    else:
        print(f"Unknown command: {command}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()
